import type { Metadata } from "next";
import Link from "next/link";
import { AppProvider } from "@/components/AppProvider";
import "@/styles/globals.css";

export const metadata: Metadata = {
  title: {
    default: "My Blog",
    template: "%s - My Blog",
  },
  description: "A complex blog application",
  icons: {
    icon: "/favicon.ico",
  },
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en">
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link
          href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&display=swap"
          rel="stylesheet"
        />
      </head>
      <body>
        <AppProvider>
          <div className="app-container">
            <header>
              <h1>My Blog</h1>
              <nav>
                <Link href="/">Home</Link>
                <Link href="/blog">Blog</Link>
              </nav>
            </header>
            <main>{children}</main>
            <footer>
              <p>&copy; 2024 My Blog</p>
            </footer>
          </div>
        </AppProvider>
      </body>
    </html>
  );
}

"use client";

import { createContext, useContext, useState, type ReactNode } from "react";

type AppContextValue = {
  theme: "light" | "dark";
  setTheme: (theme: "light" | "dark") => void;
};

const AppContext = createContext<AppContextValue | null>(null);

export function AppProvider({ children }: { children: ReactNode }) {
  const [theme, setTheme] = useState<"light" | "dark">("light");

  return (
    <AppContext.Provider value={{ theme, setTheme }}>
      {children}
    </AppContext.Provider>
  );
}

export function useAppContext(): AppContextValue {
  const context = useContext(AppContext);
  if (!context) {
    throw new Error("useAppContext must be used within AppProvider");
  }
  return context;
}

import Link from "next/link";
import type { Metadata } from "next";

export const metadata: Metadata = {
  title: "Home",
  description: "Welcome to my blog homepage",
  openGraph: {
    title: "Home - My Blog",
  },
};

type Post = {
  id: number;
  title: string;
  body: string;
  userId: number;
};

async function getRecentPosts(): Promise<Post[]> {
  const res = await fetch("https://jsonplaceholder.typicode.com/posts?_limit=5");
  if (!res.ok) {
    throw new Error("Failed to fetch posts");
  }
  return res.json();
}

export default async function HomePage() {
  const posts = await getRecentPosts();
  const timestamp = new Date().toISOString();

  return (
    <div>
      <h1>Welcome to My Blog</h1>
      <p>Server-side rendered at: {timestamp}</p>

      <h2>Recent Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <Link href={`/blog/${post.id}`}>{post.title}</Link>
          </li>
        ))}
      </ul>

      <Link href="/blog">
        <button type="button">View All Posts</button>
      </Link>
    </div>
  );
}

import Link from "next/link";
import type { Metadata } from "next";

export const metadata: Metadata = {
  title: "Blog",
  description: "All blog posts",
};

// ISR: revalidate at most every 60 seconds
export const revalidate = 60;

type Post = {
  id: number;
  title: string;
  body: string;
  userId: number;
};

async function getPosts(): Promise<Post[]> {
  const res = await fetch("https://jsonplaceholder.typicode.com/posts");
  if (!res.ok) {
    throw new Error("Failed to fetch posts");
  }
  return res.json();
}

export default async function BlogIndex() {
  const posts = await getPosts();

  return (
    <div>
      <h1>All Blog Posts</h1>

      <div className="posts-grid">
        {posts.map((post) => (
          <div key={post.id} className="post-card">
            <h2>
              <Link href={`/blog/${post.id}`}>{post.title}</Link>
            </h2>
            <p>{post.body.substring(0, 100)}...</p>
            <Link href={`/blog/${post.id}`}>
              <button type="button">Read More</button>
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

import Link from "next/link";
import { notFound } from "next/navigation";
import type { Metadata } from "next";

type Props = {
  params: Promise<{ id: string }>;
};

type Post = {
  id: number;
  title: string;
  body: string;
  userId: number;
};

type Comment = {
  id: number;
  name: string;
  email: string;
  body: string;
  postId: number;
};

// Generate static params for the first 10 posts
export async function generateStaticParams(): Promise<{ id: string }[]> {
  const res = await fetch("https://jsonplaceholder.typicode.com/posts");
  if (!res.ok) {
    throw new Error("Failed to fetch posts for static generation");
  }
  const posts: Post[] = await res.json();
  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

// ISR: revalidate at most every 5 minutes
export const revalidate = 300;

async function getPost(id: string): Promise<Post> {
  const res = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}`,
  );
  if (!res.ok) {
    throw new Error("Failed to fetch post");
  }
  return res.json();
}

async function getComments(id: string): Promise<Comment[]> {
  const res = await fetch(
    `https://jsonplaceholder.typicode.com/posts/${id}/comments`,
  );
  if (!res.ok) {
    throw new Error("Failed to fetch comments");
  }
  return res.json();
}

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  return {
    title: post.title,
    description: post.body.substring(0, 160),
    openGraph: {
      title: post.title,
      description: post.body.substring(0, 160),
    },
  };
}

export default async function BlogPost({ params }: Props) {
  const { id } = await params;

  const [post, comments] = await Promise.all([
    getPost(id).catch(() => null),
    getComments(id).catch(() => [] as Comment[]),
  ]);

  if (!post) {
    notFound();
  }

  return (
    <article>
      <Link href="/blog">← Back</Link>

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}

import Link from "next/link";
import type { Metadata } from "next";

export const metadata: Metadata = {
  title: "404 - Page Not Found",
  description: "The page you're looking for doesn't exist",
};

export default function NotFound() {
  return (
    <div className="error-page">
      <h1>404 - Page Not Found</h1>
      <p>The page you&apos;re looking for doesn&apos;t exist.</p>
      <Link href="/">
        <button type="button">Go Back Home</button>
      </Link>
    </div>
  );
}

"use client";

type ErrorPageProps = {
  error: Error & { digest?: string };
  reset: () => void;
};

export default function Error({ error, reset }: ErrorPageProps) {
  const statusCode =
    error.message?.includes("404") || error.message?.includes("not found")
      ? 404
      : 500;

  return (
    <div className="error-page">
      <h1>
        {statusCode === 404
          ? "A 404 error occurred"
          : "A 500 error occurred"}
      </h1>
      <p>
        {statusCode === 404
          ? "This page could not be found."
          : "Sorry, something went wrong."}
      </p>
      <button type="button" onClick={reset}>
        Try Again
      </button>
    </div>
  );
}

"use client";

type GlobalErrorProps = {
  error: Error & { digest?: string };
  reset: () => void;
};

export default function GlobalError({ error, reset }: GlobalErrorProps) {
  return (
    <html>
      <body>
        <div className="error-page">
          <h1>Something went wrong!</h1>
          <p>
            {error.message || "An unexpected error occurred."}
          </p>
          <button type="button" onClick={reset}>
            Try Again
          </button>
        </div>
      </body>
    </html>
  );
}

import { NextRequest, NextResponse } from "next/server";

type Post = {
  id: number;
  title: string;
  content: string;
};

type NewPostBody = {
  title?: string;
  content?: string;
};

// In-memory store (simulated)
const posts: Post[] = [
  { id: 1, title: "First Post", content: "This is the first post" },
  { id: 2, title: "Second Post", content: "This is the second post" },
];

export async function GET() {
  return NextResponse.json(posts);
}

export async function POST(request: NextRequest) {
  const body: NewPostBody = await request.json();
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json(
      { error: "Title and content are required" },
      { status: 400 },
    );
  }

  const newPost: Post = {
    id: Date.now(),
    title,
    content,
  };

  posts.push(newPost);

  return NextResponse.json(newPost, { status: 201 });
}

import { NextRequest, NextResponse } from "next/server";

type Params = Promise<{ id: string }>;

type Post = {
  id: number;
  title: string;
  content: string;
  createdAt: string;
  updatedAt?: string;
};

type UpdateBody = {
  title?: string;
  content?: string;
};

export async function GET(
  _request: NextRequest,
  { params }: { params: Params },
) {
  const { id } = await params;
  const postId = parseInt(id);

  const post: Post = {
    id: postId,
    title: `Post ${postId}`,
    content: `This is the content for post ${postId}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(
  request: NextRequest,
  { params }: { params: Params },
) {
  const { id } = await params;
  const postId = parseInt(id);
  const body: UpdateBody = await request.json();
  const { title, content } = body;

  const updatedPost: Post & { updatedAt: string } = {
    id: postId,
    title: title ?? `Post ${postId}`,
    content: content ?? `Updated content for post ${postId}`,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(
  _request: NextRequest,
  { params }: { params: Params },
) {
  const { id } = await params;

  return NextResponse.json({
    message: `Post ${id} deleted successfully`,
  });
}

export async function OPTIONS(_request: NextRequest) {
  return NextResponse.json(null, {
    headers: {
      Allow: "GET, PUT, DELETE, OPTIONS",
    },
  });
}

